% do_1d_bst_run_repair_steps.m

% you need repair_steps_12_data2.m 
% in the same directory

% It has to be fs=500 Hz. It closes the gap of every 10 seconds
% that are made by drift and AD conversion limit

% the below is taking the imported continuous file and run the matlab
% command within Brainstorm loop

% Script generated by Brainstorm (14-Jul-2021)

% Run this while Brainstorm opened
% DrumDuetImprov 2026-03-08

% universal name
% list subj#1 subj#2 in the order of the file
pair = {
    'UV', 'ML';
    'LJ', 'TF';
    'CM', 'MG';
    };
npair = size(pair,1);
player = {'SubA';'SubB'};

for ipair=1:npair
    sub={pair{ipair,1};pair{ipair,2}};
    pairname = sprintf('%s_%s', sub{1}, sub{2});
    
    % loop two partners
    for isubj=1:2
        
        subjname = sub{isubj};
        playerID= player{isubj};

% Path: C:\Users\tfujioka\Documents\brainstorm_db\DrumDuetImprov\data
% Name: ML/UV_ML_01_SubB_Data/data_block001.mat

sFiles = {...
    sprintf('%s/%s_01_%s_Data/data_block001.mat',subjname,pairname,playerID), ...
    sprintf('%s/%s_02_%s_Data/data_block001.mat',subjname,pairname,playerID), ...
    sprintf('%s/%s_03_%s_Data/data_block001.mat',subjname,pairname,playerID), ...
    sprintf('%s/%s_04_%s_Data/data_block001.mat',subjname,pairname,playerID), ...
    sprintf('%s/%s_05_%s_Data/data_block001.mat',subjname,pairname,playerID), ...
    sprintf('%s/%s_06_%s_Data/data_block001.mat',subjname,pairname,playerID), ...
    sprintf('%s/%s_07_%s_Data/data_block001.mat',subjname,pairname,playerID), ...
    sprintf('%s/%s_08_%s_Data/data_block001.mat',subjname,pairname,playerID), ...
    };

             
% Start a new report
bst_report('Start', sFiles);


% Process: Run Matlab command
sFiles = bst_process('CallProcess', 'process_matlab_eval', sFiles, [], ...
    'matlab',      ['Data = repair_steps_12_data2(Data,TimeVector);'], ...
    'sensortypes', 'MEG, EEG', ...
    'overwrite',   0);

% Save and display report
ReportFile = bst_report('Save', sFiles);
% bst_report('Open', ReportFile);  % commented out: Java NullPointerException on macOS
% bst_report('Export', ReportFile, ExportDir);

    end % isubj
end % ipair

